    def test_import(self):
        self.assertEqual(Order.objects.all().count(), 0)
        do_import_orders(ContentFile(self.csv_data.encode('utf-8')))
        self.assertEqual(Order.objects.all().count(), 2)
        self.assertEqual(OrderItem.objects.all().count(), 8)
        self.assertEqual(CatafalqueData.objects.all().count(), 1)
        self.assertEqual(CoffinData.objects.all().count(), 2)

    def test_view(self):
        self.assertEqual(Order.objects.all().count(), 0)
        r = self.ugh_client.post('/import/orders/', data={'orders-csv': open(self.csv_path)})
        self.assertEqual(r.status_code, 302)
        self.assertEqual(Order.objects.all().count(), 2) # one duplicated INN

    def test_duplicate(self):
        self.assertEqual(Order.objects.all().count(), 0)
        r = self.ugh_client.post('/import/orders/', data={'orders-csv': open(self.csv_path)})
        self.assertEqual(r.status_code, 302)
        self.assertEqual(Order.objects.all().count(), 2) # one duplicated INN

        self.assertEqual(Order.objects.all().count(), 2)
        r = self.ugh_client.post('/import/orders/', data={'orders-csv': open(self.csv_path)})
        self.assertEqual(r.status_code, 302)
        self.assertEqual(Order.objects.all().count(), 2) # all 12 duplicates


